import{_ as e,c as r,o,ae as i}from"./chunks/framework.CDjunVez.js";const G=JSON.parse('{"title":"Gmail 導入 Gemini AI：30 億用戶的平台，正在殺死寄生在它身上的服務","description":"Google 宣布 Gmail 進入 Gemini 時代，22 年來最大更新。當平台商開始做第三方的功能，那些靠 Gmail 吃飯的 AI 外掛和服務，還有活路嗎？","frontmatter":{"title":"Gmail 導入 Gemini AI：30 億用戶的平台，正在殺死寄生在它身上的服務","description":"Google 宣布 Gmail 進入 Gemini 時代，22 年來最大更新。當平台商開始做第三方的功能，那些靠 Gmail 吃飯的 AI 外掛和服務，還有活路嗎？","date":"2026-01-08T00:00:00.000Z","author":"Clement Tang","tags":["Google","Gmail","Gemini","AI","平台競爭","社群貼文"],"category":"articles","status":"published","lastModified":"2026-01-27T00:00:00.000Z"},"headers":[],"relativePath":"articles/2026-01-08-gmail-gemini-ai-platform-competition.md","filePath":"articles/2026-01-08-gmail-gemini-ai-platform-competition.md"}'),t={name:"articles/2026-01-08-gmail-gemini-ai-platform-competition.md"};function l(n,a,m,s,p,h){return o(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="gmail-導入-gemini-ai-30-億用戶的平台-正在殺死寄生在它身上的服務" tabindex="-1">Gmail 導入 Gemini AI：30 億用戶的平台，正在殺死寄生在它身上的服務 <a class="header-anchor" href="#gmail-導入-gemini-ai-30-億用戶的平台-正在殺死寄生在它身上的服務" aria-label="Permalink to &quot;Gmail 導入 Gemini AI：30 億用戶的平台，正在殺死寄生在它身上的服務&quot;">​</a></h1><blockquote><p>Google 宣布 Gmail 進入 Gemini 時代，22 年來最大更新。當平台商開始做第三方的功能，那些靠 Gmail 吃飯的 AI 外掛和服務，還有活路嗎？</p></blockquote><hr><h2 id="_22-年來最大更新" tabindex="-1">22 年來最大更新 <a class="header-anchor" href="#_22-年來最大更新" aria-label="Permalink to &quot;22 年來最大更新&quot;">​</a></h2><p>2026 年 1 月 8 日，Google 正式宣布：<strong>Gmail 進入 Gemini 時代。</strong></p><p>這是 Gmail 自 2004 年推出以來最大規模的更新。</p><p>30 億用戶的信箱，一夜之間多了 AI 大腦。</p><p>Google 的產品副總裁 Blake Barnes 說得直白：「85% 的用戶認為，當 AI 能讀懂他們的郵件內容，才是真正有用的 AI。」</p><p>翻譯一下：<strong>Google 要用你的郵件資料，訓練出最懂你的 AI 助理。</strong></p><p>而這個助理，是免費的。</p><hr><h2 id="四個讓第三方服務冒冷汗的新功能" tabindex="-1">四個讓第三方服務冒冷汗的新功能 <a class="header-anchor" href="#四個讓第三方服務冒冷汗的新功能" aria-label="Permalink to &quot;四個讓第三方服務冒冷汗的新功能&quot;">​</a></h2><p><strong>AI Inbox</strong> 是這次更新的重頭戲。Gmail 側邊欄多了一個帶閃光圖標的「AI Inbox」選項，點進去不再是一封封郵件，而是「建議待辦」和「需要跟進的主題」兩大區塊。前者列出帳單、提醒、需要回覆的事項；後者則是重要但不緊急的事，附帶脈絡說明。這不是信箱，這是個人助理。</p><p><strong>AI 搜尋</strong> 讓你可以用問句找郵件。「去年幫我報價浴室裝修的水電師傅是誰？」以前你得翻好幾封郵件，現在 Gemini 直接給你答案。自然語言搜尋，取代關鍵字搜尋。</p><p><strong>進階校對</strong> 功能會分析你的草稿，檢查文法錯誤、語氣是否得體、句子是否太冗長、用詞是否精準。媒體直接稱這個功能為「Grammarly for Gmail」——對於剛被 Grammarly 收購的 Superhuman 來說，這是雙重打擊。</p><p><strong>三個功能免費開放</strong>——原本要付費的 Help Me Write（一句話生成整封郵件）、郵件串摘要（長對話一鍵總結）、個人化建議回覆（AI 學習你的語氣和習慣），現在美國用戶全部免費。</p><hr><h2 id="這些功能-聽起來很熟悉" tabindex="-1">這些功能，聽起來很熟悉？ <a class="header-anchor" href="#這些功能-聽起來很熟悉" aria-label="Permalink to &quot;這些功能，聽起來很熟悉？&quot;">​</a></h2><p>沒錯。</p><p>「郵件摘要」是 Superhuman 的招牌功能。「AI 寫信」是各種 Gmail 外掛都在做的事。「智慧搜尋」更是一堆第三方服務的賣點。</p><p><strong>現在，Google 全部做了。而且免費。</strong></p><hr><h2 id="_30-億用戶的分發優勢" tabindex="-1">30 億用戶的分發優勢 <a class="header-anchor" href="#_30-億用戶的分發優勢" aria-label="Permalink to &quot;30 億用戶的分發優勢&quot;">​</a></h2><p>讓我們看一組數字。</p><p>2025 年 1 月，ChatGPT 市佔率 87.2%，Gemini 市佔率 5.4%。2026 年 1 月，ChatGPT 降到 68%，Gemini 升到 18.2%。<strong>一年之內，Gemini 的市佔率成長了 3.4 倍。</strong></p><p>怎麼做到的？不是因為 Gemini 比 ChatGPT 聰明多少。是因為 Google 把 Gemini 塞進了每一個產品裡——Gmail 有 30 億用戶，Chrome 有 30 億裝置，Android 有 30 億裝置，Google Search 全球市佔 90%。</p><p><strong>OpenAI 要用戶主動來找 ChatGPT。Google 直接把 Gemini 送到用戶面前。</strong></p><p>根據 Similarweb 的數據，在 Android 上透過系統內建使用 Gemini 的用戶，是主動下載 Gemini App 用戶的兩倍。</p><p>更厲害的是，Gmail 的 AI 功能預設開啟。如果用戶想關閉 AI，必須連帶關閉所有 Gmail 智慧功能——包括收件匣自動分類、郵件排序等。這種綑綁式設計，讓用戶很難真正拒絕 AI，也讓第三方服務更難說服用戶「來用我們的 AI 吧」。</p><hr><h2 id="平台商殺死寄生應用的經典劇本" tabindex="-1">平台商殺死寄生應用的經典劇本 <a class="header-anchor" href="#平台商殺死寄生應用的經典劇本" aria-label="Permalink to &quot;平台商殺死寄生應用的經典劇本&quot;">​</a></h2><p>這個故事，科技業已經看過很多次了。</p><p><strong>iOS 內建功能 vs. App Store 應用</strong>——手電筒 App、計算機 App、螢幕錄影 App、密碼管理 App，iOS 全部內建了。每次 Apple 在 WWDC 宣布新功能，都有一批開發者的商業模式被宣判死刑。</p><p><strong>Google Maps vs. 導航 App</strong>——還記得 Garmin 和 TomTom 嗎？當 Google Maps 免費提供導航功能，那些賣導航軟體的公司，市值瞬間蒸發。</p><p><strong>Spotify vs. 唱片公司</strong>——Spotify 擁有用戶和播放列表資料，唱片公司擁有音樂版權。誰的議價能力更強？<strong>掌握分發通路的人，永遠有主動權。</strong></p><hr><h2 id="grammarly-superhuman-的回應" tabindex="-1">Grammarly-Superhuman 的回應 <a class="header-anchor" href="#grammarly-superhuman-的回應" aria-label="Permalink to &quot;Grammarly-Superhuman 的回應&quot;">​</a></h2><p>Superhuman 曾是矽谷最知名的付費郵件服務，月費 30 美元。2025 年 7 月，它被 Grammarly 收購，合併後的公司現在也叫 Superhuman。</p><p>Superhuman 的數據其實很亮眼：超過 85% 的用戶啟用了 AI 功能，使用後每小時能發送和回覆的郵件數量提升 72%。但問題是基數——Superhuman 的 85% 採用率很高，Gmail 即使只有 10% 用戶使用 AI，絕對數量也遠超 Superhuman 全部用戶。</p><p>面對 Google 的免費攻勢，創辦人 Rahul Vohra 說：「Superhuman 比 Google 的 AI 更個人化、更有脈絡。Google 的 AI 聽起來很制式。」他還強調：「我們的 AI 搜尋速度是 Gmail 的 2-3 倍。」</p><p>TechView 的 AI 生產力分析師 Amanda Klein 認為，Grammarly-Superhuman 的優勢在於深度語言模型和個人化能力——語氣、文法、清晰度一直是 Grammarly 的強項，現在加上 Superhuman 的速度和意圖理解。但她也坦言，當免費產品達到「夠好」的程度，付費產品的差異化空間就會被壓縮。</p><p><strong>多少人願意為「更快一點」和「更個人化一點」每月付 30 美元？</strong> 當免費的 80 分選項出現，付費的 90 分選項就很難賣了。這或許也解釋了為什麼 Superhuman 在 Google 全面進攻之前，就選擇與 Grammarly 合併——單打獨鬥，越來越難。</p><hr><h2 id="第三方服務的生存空間" tabindex="-1">第三方服務的生存空間 <a class="header-anchor" href="#第三方服務的生存空間" aria-label="Permalink to &quot;第三方服務的生存空間&quot;">​</a></h2><p>Google 做了郵件 AI，但不是所有功能都被取代。</p><p><strong>郵件追蹤</strong>——知道對方什麼時候開信、開了幾次、用什麼裝置開。這是 Google 不太可能做的功能，隱私爭議太大。</p><p><strong>團隊協作</strong>——共享信箱、郵件指派、狀態追蹤。企業用戶的需求，不是個人 AI 助理能滿足的。</p><p><strong>行銷整合</strong>——把郵件簽名變成行銷素材、追蹤點擊率、A/B 測試。這是 CRM 和 MarTech 的領域，不是 Gmail 的本業。</p><p><strong>資安與合規</strong>——金融業、醫療業、法律業有嚴格的資料處理規範。「Google 會讀你的信」這件事，在這些產業是減分。</p><p>對 Superhuman 來說，未來的路大概就是這幾條：往企業市場深耕，強化 Grammarly 生態的整合優勢，以及開發 Google 不願意碰的功能。單靠「更快更個人化」，已經不夠了。</p><hr><h2 id="反壟斷的陰影" tabindex="-1">反壟斷的陰影 <a class="header-anchor" href="#反壟斷的陰影" aria-label="Permalink to &quot;反壟斷的陰影&quot;">​</a></h2><p>Google 的分發優勢，已經引起監管機構的注意。</p><p>在美國反壟斷聽證會上，法官 Mehta 直接質疑：「如果要使用 Google Maps 和 YouTube，就必須安裝 Gemini，這不是跟你們當年在搜尋市場做的事一樣嗎？」</p><p>美國司法部的立場更明確：<strong>不應該讓 Google 用相同的策略，在 AI 市場複製它在搜尋市場的壟斷地位。</strong></p><p>2025 年 9 月的判決，法官已經警告 Google：「不得在生成式 AI 產品上使用相同的反競爭手段。」但警告歸警告，在判決生效之前，Google 的整合速度只會更快。</p><hr><h2 id="真正的戰場-ai-的分發通路" tabindex="-1">真正的戰場：AI 的分發通路 <a class="header-anchor" href="#真正的戰場-ai-的分發通路" aria-label="Permalink to &quot;真正的戰場：AI 的分發通路&quot;">​</a></h2><p>這場 Gmail AI 的戰爭，表面上是功能之爭，<strong>本質上是 AI 分發通路之爭。</strong></p><p>ChatGPT 很強，但用戶要主動開啟一個新網站或 App 才能用，每一次「主動」都是摩擦力。Google 不一樣——打開 Gmail，AI 就在那裡；打開 Chrome，AI 就在那裡；打開手機，AI 就在那裡。<strong>零摩擦力。</strong></p><p>如果你的 AI 服務是「寄生」在 Google 的平台上——Gmail 外掛、Chrome 擴充功能——那麼你的分發通路，掌握在競爭對手手裡。Google 隨時可以改變 API 政策、推出相同功能、把你從商店下架。這不是假設，這是正在發生的事。</p><hr><h2 id="三個給創業者的啟示" tabindex="-1">三個給創業者的啟示 <a class="header-anchor" href="#三個給創業者的啟示" aria-label="Permalink to &quot;三個給創業者的啟示&quot;">​</a></h2><p><strong>不要在別人的平台上建立核心價值。</strong> 如果你的產品 100% 依賴 Gmail API，你的命運就 100% 掌握在 Google 手裡。自己的分發通路，才是真正的護城河。</p><p><strong>做平台商不願意做的事。</strong> Google 不會做侵犯隱私的郵件追蹤，不會做垂直產業的合規方案，不會做高接觸的企業服務。這些是第三方的機會。</p><p><strong>速度和體驗的差異，不足以支撐付費。</strong>「比 Gmail 快 2 倍」聽起來很厲害，但對大多數用戶來說，免費的「夠快」勝過付費的「更快」。差異化要在功能層面，不是性能層面。</p><hr><h2 id="結語-平台的詛咒與祝福" tabindex="-1">結語：平台的詛咒與祝福 <a class="header-anchor" href="#結語-平台的詛咒與祝福" aria-label="Permalink to &quot;結語：平台的詛咒與祝福&quot;">​</a></h2><p>Gmail 加入 AI 功能，對用戶是好事——免費、方便、整合度高。</p><p>但對整個生態系統來說，這是一個警訊：<strong>當平台商開始認真做某件事，寄生在平台上的服務就會被擠壓。</strong></p><p>這不是 Google 邪惡，這是商業邏輯。擁有 30 億用戶的公司，自然會想辦法讓這 30 億用戶用更多自己的服務。</p><p><strong>對創業者來說，教訓很簡單：不要把房子蓋在別人的土地上。或者，至少要有一個備案。</strong></p><hr><h2 id="關鍵數據一覽" tabindex="-1">關鍵數據一覽 <a class="header-anchor" href="#關鍵數據一覽" aria-label="Permalink to &quot;關鍵數據一覽&quot;">​</a></h2><p><strong>Gmail Gemini 更新（2026/1/8）：</strong> 影響用戶 30 億，主要功能包括 AI Inbox、AI 搜尋、進階校對、Help Me Write。免費開放功能為郵件摘要、建議回覆、Help Me Write；AI 搜尋答案和 AI 校對則需要 Google AI Pro/Ultra。</p><p><strong>AI 聊天機器人市場變化（2025-2026）：</strong> ChatGPT 從 87.2% 降至 68%，Gemini 從 5.4% 升至 18.2%，成長 3.4 倍。</p><p><strong>Google 分發優勢：</strong> Gmail 用戶 30 億、Chrome 裝置 30 億、Android 裝置 30 億，系統內建 vs App 使用比例為 2:1。</p><p><strong>Superhuman 數據：</strong> AI 功能採用率 85%，使用後郵件處理效率提升 72%，月費 $30，2025 年 7 月被 Grammarly 收購。</p><p><strong>其他受影響的第三方服務：</strong> Boomerang、Sortd，以及各類 Gmail AI 外掛。</p><hr><h2 id="延伸思考" tabindex="-1">延伸思考 <a class="header-anchor" href="#延伸思考" aria-label="Permalink to &quot;延伸思考&quot;">​</a></h2><p>如果你是 Superhuman 的創辦人，接下來會怎麼調整策略？監管機構能否有效限制科技巨頭的平台優勢？下一個被「平台化」的 AI 應用場景會是什麼？</p><p>歡迎在留言區分享你的看法。</p><hr><h2 id="參考資料" tabindex="-1">參考資料 <a class="header-anchor" href="#參考資料" aria-label="Permalink to &quot;參考資料&quot;">​</a></h2><ol><li><a href="https://techcrunch.com/2026/01/08/gmail-debuts-a-personalized-ai-inbox-ai-overviews-in-search-and-more/" target="_blank" rel="noreferrer">Gmail debuts a personalized AI Inbox, AI Overviews in search, and more | TechCrunch</a></li><li><a href="https://9to5google.com/2026/01/08/gmail-ai-inbox/" target="_blank" rel="noreferrer">Google announces the future of Gmail with AI Inbox &amp; new AI Overview search | 9to5Google</a></li><li><a href="https://blog.google/products-and-platforms/products/gmail/gmail-is-entering-the-gemini-era/" target="_blank" rel="noreferrer">Gmail is entering the Gemini era | Google Blog</a></li><li><a href="https://www.tomsguide.com/ai/gmails-biggest-update-in-20-years-5-ai-features-that-could-change-email-forever" target="_blank" rel="noreferrer">Gmail&#39;s biggest update in 20 years: 5 AI features that could change email forever | Tom&#39;s Guide</a></li><li><a href="https://www.cnbc.com/2026/01/08/google-adds-gemini-features-to-gmail-message-summaries-proofreading-.html" target="_blank" rel="noreferrer">Google is unleashing Gemini AI features on Gmail | CNBC</a></li><li><a href="https://vertu.com/lifestyle/ai-chatbot-market-share-2026-chatgpt-drops-to-68-as-google-gemini-surges-to-18-2/" target="_blank" rel="noreferrer">AI Chatbot Market Share 2026: ChatGPT vs Gemini | Similarweb Analysis</a></li><li><a href="https://www.inc.com/ben-sherry/email-innovator-superhuman-says-its-ai-search-is-twice-fast-as-gmail.html" target="_blank" rel="noreferrer">Email Innovator Superhuman Says Its AI Search Is Twice as Fast as Gmail&#39;s | Inc.</a></li><li><a href="https://techcrunch.com/2025/07/01/grammarly-acquires-ai-email-client-superhuman/" target="_blank" rel="noreferrer">Grammarly acquires AI email client Superhuman | TechCrunch</a></li><li><a href="https://www.aicerts.ai/news/grammarly-adds-superhuman-email-app-to-ai-platform/" target="_blank" rel="noreferrer">Grammarly Adds Superhuman Email App to Expand Its AI Platform | AI CERTs</a></li><li><a href="https://www.theregister.com/2026/01/08/google_gemini_gmail/" target="_blank" rel="noreferrer">Google decides to bring Gmail into &#39;the Gemini era&#39; | The Register</a></li></ol><hr><h2 id="更新記錄" tabindex="-1">更新記錄 <a class="header-anchor" href="#更新記錄" aria-label="Permalink to &quot;更新記錄&quot;">​</a></h2><ul><li><strong>2026-01-08：</strong> 建立文章，分析 Gmail Gemini 更新對第三方 AI 服務的平台衝擊</li><li><strong>2026-01-08：</strong> 補充 Superhuman 衝擊分析、分析師觀點、用戶數據與預設開啟機制</li></ul><hr>',90)])])}const u=e(t,[["render",l]]);export{G as __pageData,u as default};
